{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以...嗎？' to politely ask for permission or request an action. This is a standard polite request form in Taiwanese Mandarin.",
      "title": "Polite Request with 可以...嗎？",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When asking for permission to do something", "When requesting an item or service from a shop or café"],
      "when_not_to_use": ["When making a direct command or demand", "When speaking to close friends in informal settings (use 我要 instead)"],
      "pragmatic_notes": "In Taiwan, using 可以...嗎？ is very common and polite. It shows respect and is appropriate for interactions with shop staff, waiters, or strangers.",
      "word_order_notes": "The structure is fixed: 可以 + verb + object + 嗎. Do not place 嗎 before the verb.",
      "english_contrast": "English uses 'Can I...?' or 'May I...?' with subject inversion. Chinese keeps the subject optional and uses 可以 at the start.",
      "korean_contrast": "Korean uses '~을/를 해도 될까요?' which is similar in politeness but has a different word order (object + verb + question ending).",
      "negative_examples": [
        {
          "text": "可以嗎我喝水？",
          "error": "Word order is wrong. 可以 must come before the verb, not at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以嗎我喝水？",
          "error": "Word order is wrong. 可以 must come before the verb, not at the end."
        }
      ],
      "transformation_drills": ["Change '我要一杯咖啡' to a polite request using 可以...嗎？", "Change '請給我水' to a polite request using 可以...嗎？"],
      "production_drills": ["Ask for a cup of tea politely.", "Ask if you can sit here."],
      "common_error_patterns": ["Placing 嗎 before the verb", "Omitting 可以 and using 嗎 directly after the verb"],
      "repair_feedback": {
        "word_order": "Remember: 可以 + verb + object + 嗎. For example: 可以喝水嗎？",
        "politeness": "Using 可以...嗎？ is polite. Avoid using 我要 directly with strangers.",
        "vocabulary": "Use appropriate verbs like 喝, 吃, 坐, 看, 試."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express a desire or want for an object. It is softer than '要' and is often used in polite requests.",
      "title": "Expressing Desire with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When expressing a wish or preference in a shop"],
      "when_not_to_use": ["When making a direct command (use 要 instead)", "When asking for permission (use 可以...嗎？)"],
      "pragmatic_notes": "In Taiwan, 想要 is polite and commonly used in service settings. It implies a desire rather than a demand.",
      "word_order_notes": "想要 is followed directly by the object. No additional verb is needed. Example: 想要一杯咖啡.",
      "english_contrast": "English uses 'I would like...' which is similar in politeness. Chinese does not require a subject if it is clear from context.",
      "korean_contrast": "Korean uses '~을/를 원하다' or '~고 싶다' which are similar but require a verb ending.",
      "negative_examples": [
        {
          "text": "想要嗎一杯咖啡？",
          "error": "嗎 is not needed here. 想要 is a statement, not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "想要嗎一杯咖啡？",
          "error": "嗎 is not needed here. 想要 is a statement, not a question."
        }
      ],
      "transformation_drills": ["Change '我要一杯水' to a softer request using 想要", "Change '我想喝咖啡' to use 想要 directly"],
      "production_drills": ["Order a latte using 想要.", "Say you would like a bag."],
      "common_error_patterns": ["Adding 嗎 after 想要", "Using 想要 with a verb unnecessarily (e.g., 想要喝 instead of 想要一杯咖啡)"],
      "repair_feedback": {
        "word_order": "Use 想要 + object. Example: 想要一杯紅茶.",
        "politeness": "想要 is polite. Avoid using 要 in formal requests.",
        "vocabulary": "Use object nouns like 咖啡, 茶, 水, 袋子."
      }
    },
    {
      "pattern": "不好意思，[request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' as a polite softener before making a request. It shows apology for the inconvenience and is very common in Taiwanese service interactions.",
      "title": "Polite Softener with 不好意思",
      "meaning": "Excuse me, sorry to bother...",
      "when_to_use": ["When starting a request in a shop or café", "When asking for help or information"],
      "when_not_to_use": ["When the request is very casual among friends (use 請問 instead)", "When you are angry or frustrated"],
      "pragmatic_notes": "In Taiwan, 不好意思 is used frequently to soften requests. It is more polite than 請問 in some contexts and shows humility.",
      "word_order_notes": "不好意思 comes at the beginning of the sentence, followed by the request. Example: 不好意思，可以給我一杯水嗎？",
      "english_contrast": "English uses 'Excuse me' or 'Sorry to bother you' at the start. Chinese uses 不好意思 similarly.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' which are similar but more formal.",
      "negative_examples": [
        {
          "text": "可以給我一杯水嗎不好意思？",
          "error": "不好意思 should come at the beginning, not the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以給我一杯水嗎不好意思？",
          "error": "不好意思 should come at the beginning, not the end."
        }
      ],
      "transformation_drills": ["Add 不好意思 to the beginning of '可以給我一杯咖啡嗎？'", "Change '請問，有紅茶嗎？' to use 不好意思"],
      "production_drills": ["Politely ask for a menu using 不好意思.", "Politely ask for a tissue."],
      "common_error_patterns": ["Placing 不好意思 at the end of the sentence", "Using 不好意思 too many times in one sentence"],
      "repair_feedback": {
        "word_order": "Put 不好意思 at the start. Example: 不好意思，可以...嗎？",
        "politeness": "Using 不好意思 makes your request more polite and natural in Taiwan.",
        "vocabulary": "Combine with polite request patterns like 可以...嗎？ or 想要."
      }
    }
  ]
}
